import logging
from django.conf import settings
from django.http import JsonResponse

logger = logging.getLogger('middleware')


class TokenAuthMiddleware:
    """Validates Bearer tokens for API requests.

    Checks the Authorization header for valid bearer tokens
    and attaches the authenticated user to the request.
    """

    def __init__(self, get_response):
        self.get_response = get_response
        self.exempt_paths = [
            '/api/v1/health/',
            '/api/v1/users/login/',
            '/api/v1/users/register/',
        ]

    def __call__(self, request):
        if any(request.path.startswith(p) for p in self.exempt_paths):
            return self.get_response(request)

        auth_header = request.META.get('HTTP_AUTHORIZATION', '')
        if not auth_header.startswith('Bearer '):
            return JsonResponse(
                {'error': 'Authentication required', 'code': 'AUTH_REQUIRED'},
                status=401
            )

        token = auth_header[7:]
        # Token validation delegated to DRF TokenAuthentication
        request.META['HTTP_X_VERIFIED_TOKEN'] = token
        return self.get_response(request)

